const config = $('Config').first().json;
const rows = $input.all().map(i => i.json);

const topLocal = config.top_local || 10;
const topRegional = config.top_regional || 7;
const topIntl = config.top_international || 5;

// Filtrer les lignes de séparateur (pas de société)
const dataRows = rows.filter(r => r.Société && r.Bucket && ['LOCAL','REGIONAL','INTERNATIONAL'].includes(r.Bucket));

// Top N par bucket
const bucketCount = {};
const selected = [];

for (const row of dataRows) {
  const bucket = row.Bucket;
  const limit = bucket === 'LOCAL' ? topLocal : bucket === 'REGIONAL' ? topRegional : topIntl;
  bucketCount[bucket] = (bucketCount[bucket] || 0) + 1;
  if (bucketCount[bucket] <= limit) {
    selected.push({
      bucket,
      rang: bucketCount[bucket],
      societe: row.Société,
      pays: row.Pays,
      score_bm: parseFloat(row['Score Total']) || 0,
      nb_awards: parseInt(row['Nb Awards']) || 0,
      nb_projets: parseInt(row['Nb Projets']) || 0,
      dernier_award: row['Dernier Award'] || '',
      justification_bm: row['Justification (top 3 awards)'] || '',
      urls_bm: row['URLs'] || '',
      champ_libre: config.champ_libre,
      sheet_output_id: config.sheet_output_id,
      openai_key: config.openai_key,
      brave_key: config.brave_key
    });
  }
}

return selected.map(s => ({ json: s }));

function buildAwardsDetail(justif, urls) {
  if (!justif || !urls) return '';
  const urlList = urls.split('|').map(u => u.trim()).filter(Boolean);
  const pattern = /\[(\d{4}-\d{2})\]\s([^\[|]+)/g;
  let match;
  const awards = [];
  let i = 0;
  while ((match = pattern.exec(justif)) !== null) {
    awards.push({
      date: match[1],
      titre: match[2].trim().replace(/\s*\|.*$/, ''),
      url: urlList[i] || ''
    });
    i++;
  }
  return JSON.stringify(awards);
}

const item = $('Prompt').item.json;
const openaiResponse = $json;

let analysis = {};
try {
  const output = openaiResponse?.output || [];
  const msgBlock = output.find(b => b.type === 'message');
  const content = msgBlock?.content?.find(c => c.type === 'output_text')?.text || '{}';
  const clean = content.replace(/```json|```/g, '').trim();
  analysis = JSON.parse(clean);
} catch(e) {
  analysis = {
    description: 'Analyse non disponible',
    analyse: '',
    points_forts: [],
    domaines: [],
    fit_level: 'Unclear',
    score_pertinence: 0,
    red_flags: [],
    site_officiel: null,
    email_contact: null,
    linkedin: null,
    confidence: 'Low'
  };
}

return {
  json: {
    Bucket: item.bucket,
    Rang: item.rang,
    Société: item.societe,
    Pays: item.pays,
    'Score BM': item.score_bm,
    'Score Pertinence': analysis.score_pertinence || 0,
    'Fit Level': analysis.fit_level || 'Unclear',
    Confiance: analysis.confidence || 'Low',
    Description: analysis.description || '',
    Analyse: analysis.analyse || '',
    'Points Forts': Array.isArray(analysis.points_forts) ? analysis.points_forts.join(' | ') : '',
    Domaines: Array.isArray(analysis.domaines) ? analysis.domaines.join(', ') : '',
    'Red Flags': Array.isArray(analysis.red_flags) ? analysis.red_flags.join(' | ') : '',
    'Site Web': analysis.site_officiel || '',
    Contact: analysis.email_contact || '',
    LinkedIn: analysis.linkedin || '',
    'Sources BM': item.urls_bm || '',
    'Awards Detail': buildAwardsDetail(item.justification_bm, item.urls_bm),
  }
};

const allItems = $input.all().map(i => i.json);
const config = $('Config').first().json;

// Trier par bucket puis score final
const bucketOrder = { LOCAL: 0, REGIONAL: 1, INTERNATIONAL: 2 };
allItems.sort((a,b) => {
  if (a.Bucket !== b.Bucket) return bucketOrder[a.Bucket] - bucketOrder[b.Bucket];
  if (b['Score Pertinence'] !== a['Score Pertinence']) return b['Score Pertinence'] - a['Score Pertinence'];
  return b['Score BM'] - a['Score BM'];
});

// Recalculer les rangs après tri
const bucketRank = {};
for (const item of allItems) {
  bucketRank[item.Bucket] = (bucketRank[item.Bucket] || 0) + 1;
  item.Rang = bucketRank[item.Bucket];
}

return allItems.map(i => ({ json: i }));
